{policy_text}

Previous version (if provided — use to detect changes):
{previous_version}

Return ONLY this JSON structure:
{{
  "vendor": "{vendor_name}",
  "policy_type": "detected type",
  "analysis_date": "<ISO date>",
  "risk_level": "low|medium|high|critical",
  "executive_summary": "3-4 sentence plain-English summary of key findings",
  "what_changed": [
    {{"section": "...", "change": "...", "impact": "low|medium|high", "action_required": true/false}}
  ],
  "domains": {{
    "privacy_data_usage": {{
      "score": <1-10>,
      "findings": ["..."],
      "data_collected": ["..."],
      "retention_period": "...",
      "data_sharing": ["..."],
      "user_rights": ["..."],
      "lawful_basis": "...",
      "red_flags": ["..."]
    }},
    "ai_ml_training": {{
      "score": <1-10>,
      "trains_on_user_data": true/false/"unclear",
      "opt_out_available": true/false/"unclear",
      "opt_out_method": "...",
      "enterprise_exemption": true/false/"unclear",
      "findings": ["..."],
      "red_flags": ["..."]
    }},
    "security_posture": {{
      "score": <1-10>,
      "certifications": ["SOC 2", "ISO 27001", etc.],
      "encryption": "...",
      "incident_response": "...",
      "findings": ["..."],
      "red_flags": ["..."]
    }},
    "carbon_sustainability": {{
      "score": <1-10>,
      "net_zero_commitment": "...",
      "renewable_energy": "...",
      "findings": ["..."]
    }},
    "governance": {{
      "score": <1-10>,
      "gdpr_compliant": true/false/"unclear",
      "dpdp_2023_compliant": true/false/"unclear",
      "ccpa_compliant": true/false/"unclear",
      "dpa_available": true/false,
      "dpo_contact": "...",
      "findings": ["..."],
      "red_flags": ["..."]
    }}
  }},
  "deadline_actions": [
    {{"action": "...", "deadline": "...", "priority": "urgent|high|medium"}}
  ],
  "recommended_actions": [
    {{"action": "...", "effort": "low|medium|high", "impact": "low|medium|high"}}
  ],
  "opt_out_instructions": {{
    "ai_training": "step-by-step instructions or null if not applicable",
    "marketing": "step-by-step instructions or null",
    "analytics": "step-by-step instructions or null"
  }}
}}

Return ONLY the JSON. No markdown fences. No explanation.
